INSERT INTO critical_value_alert (
    register_id, patient_name, case_number, source_type, source_id, tech_name,
    critical_items, severity, reporter_id, reporter_name, doctor_id, doctor_name,
    status, reported_time, ack_deadline
) VALUES (
    #{registerId}, #{patientName}, #{caseNumber}, #{sourceType}, #{sourceId}, #{techName},
    #{criticalItems}::jsonb, #{severity}, #{reporterId}, #{reporterName}, #{doctorId}, #{doctorName},
    #{status}, #{reportedTime}, #{ackDeadline}
)

