SELECT * FROM critical_value_alert
WHERE status = 'PENDING'
  AND ack_deadline < #{now}

SELECT * FROM critical_value_alert
ORDER BY reported_time DESC
LIMIT #{limit}

mapper.update:
UPDATE critical_value_alert
SET status = #{status},
    acknowledged_time = #{acknowledgedTime}
WHERE id = #{id}

UPDATE critical_value_alert
SET status = #{status},
    handled_time = #{handledTime},
    handle_note = #{handleNote}
WHERE id = #{id}

UPDATE critical_value_alert
SET status = #{status},
    escalated_time = #{escalatedTime}
WHERE id = #{id}
